import{_ as h,C as a,o as g,c,a3 as n,E as o,w as d,j as e,a as r}from"./chunks/framework.CCylkYel.js";const m="/screens/perform/macro_rows_classic_midi.png",u="/screens/perform/macro_row_named.png",p="/screens/perform/macro_options_named_side_menu.png",N=JSON.parse('{"title":"Classic MIDI macro rows","description":"","frontmatter":{},"headers":[],"relativePath":"perform/macro-rows/classic-midi.md","filePath":"perform/macro-rows/classic-midi.md"}'),b={name:"perform/macro-rows/classic-midi.md"};function f(C,t,w,P,I,_){const l=a("ScreenHighlight"),s=a("C"),i=a("ManualRelated");return g(),c("div",null,[t[11]||(t[11]=n('<h1 id="classic-midi-macro-rows" tabindex="-1">Classic MIDI macro rows <a class="header-anchor" href="#classic-midi-macro-rows" aria-label="Permalink to &quot;Classic MIDI macro rows&quot;">​</a></h1><p>These macros <strong>send MIDI</strong> when you turn the knob — control changes, program change, channel pressure, NRPN/RPN, and (eventually) SysEx. On Perform, they all share the <strong>same row shape</strong>: message type on the left, routing in the middle, live level on the right.</p><p><img src="'+m+'" alt="Classic MIDI macro rows on Perform" class="screen"></p><table tabindex="0"><thead><tr><th>Row</th><th>Mode</th><th>Example in screenshot</th></tr></thead><tbody><tr><td><strong>0</strong></td><td>Control Change</td><td>CC <strong>74</strong> (filter cutoff), channel <strong>1</strong>, USB, LFO-modulated</td></tr><tr><td><strong>1</strong></td><td>14-bit CC</td><td>Controllers <strong>0</strong> and <strong>32</strong>, channel <strong>2</strong>, DIN Out <strong>2</strong>, narrowed range</td></tr><tr><td><strong>2</strong></td><td>NRPN</td><td>NRPN <strong>1</strong> / <strong>8</strong>, <strong>Global</strong> channel, USB</td></tr><tr><td><strong>3</strong></td><td>RPN</td><td>RPN <strong>0</strong> / <strong>1</strong>, channel <strong>10</strong>, USB + DIN Out <strong>1</strong></td></tr></tbody></table><h2 id="reading-a-classic-midi-row" tabindex="-1">Reading a classic MIDI row <a class="header-anchor" href="#reading-a-classic-midi-row" aria-label="Permalink to &quot;Reading a classic MIDI row&quot;">​</a></h2>',5)),o(l,{class:"screen-highlight--macro-rows",src:"/screens/perform/macro_rows_classic_midi.png",alt:"Classic MIDI macro rows",x:0,y:20,w:66.4,h:80,label:"Rows"},{default:d(()=>[...t[0]||(t[0]=[e("p",null,[r("Follow each row "),e("strong",null,"left to right"),r(": "),e("strong",null,"what message"),r(" → "),e("strong",null,"which controller or parameter"),r(" → "),e("strong",null,"which MIDI channel"),r(" → "),e("strong",null,"which outputs"),r(" (and LFO badge if modulated). The "),e("strong",null,"live value"),r(" sits on the far right, outside this highlight.")],-1)])]),_:1}),t[12]||(t[12]=n('<h3 id="message-type" tabindex="-1">Message type <a class="header-anchor" href="#message-type" aria-label="Permalink to &quot;Message type&quot;">​</a></h3><p>Short tag for the MIDI message the macro sends:</p><table tabindex="0"><thead><tr><th>Tag</th><th>Macro mode</th></tr></thead><tbody><tr><td><code>CC</code></td><td>Control Change (7-bit)</td></tr><tr><td><code>CC14</code></td><td>14-bit Control Change</td></tr><tr><td><code>PC</code></td><td>Program Change</td></tr><tr><td><code>AT</code></td><td>Channel Aftertouch</td></tr><tr><td><code>NRPN</code></td><td>Non-Registered Parameter Number</td></tr><tr><td><code>RPN</code></td><td>Registered Parameter Number</td></tr><tr><td><code>SYX</code></td><td>SysEx — see <a href="./sysex">SysEx on Perform</a> (guide coming soon)</td></tr></tbody></table><h3 id="controller-or-parameter-numbers" tabindex="-1">Controller or parameter numbers <a class="header-anchor" href="#controller-or-parameter-numbers" aria-label="Permalink to &quot;Controller or parameter numbers&quot;">​</a></h3><p>Which MIDI address the knob drives:</p><table tabindex="0"><thead><tr><th>Mode</th><th>This field shows</th></tr></thead><tbody><tr><td><strong>CC</strong></td><td>The <strong>control change number</strong> (e.g. <strong>74</strong> for cutoff, <strong>7</strong> for volume)</td></tr><tr><td><strong>CC14</strong>, <strong>NRPN</strong>, <strong>RPN</strong>, <strong>SysEx</strong></td><td><strong>MSB/LSB</strong> pair (e.g. <strong>0/32</strong> — the two controller numbers for a 14-bit message)</td></tr><tr><td><strong>PC</strong>, <strong>AT</strong></td><td><em>(nothing — the message type alone is enough)</em></td></tr></tbody></table><p>These are the same numbers you set in the macro grid (<strong>MSB</strong> / <strong>LSB</strong> fields).</p><h3 id="midi-channel" tabindex="-1">MIDI channel <a class="header-anchor" href="#midi-channel" aria-label="Permalink to &quot;MIDI channel&quot;">​</a></h3><p><code>Glob</code> = <strong>Global</strong> — uses the project’s global channel setting.<br><code>Ch1</code>–<code>Ch16</code> = fixed channel for this macro only.</p><h3 id="output-ports" tabindex="-1">Output ports <a class="header-anchor" href="#output-ports" aria-label="Permalink to &quot;Output ports&quot;">​</a></h3><p>Three boxes show where the message is sent:</p><table tabindex="0"><thead><tr><th>Box</th><th>Port</th></tr></thead><tbody><tr><td><strong>U</strong></td><td>USB MIDI</td></tr><tr><td><strong>1</strong></td><td>DIN Out 1</td></tr><tr><td><strong>2</strong></td><td>DIN Out 2</td></tr></tbody></table><p>A <strong>bright</strong> box is enabled for this macro; a dim box is off.</p><h3 id="lfo-modulation-badge" tabindex="-1">LFO modulation badge <a class="header-anchor" href="#lfo-modulation-badge" aria-label="Permalink to &quot;LFO modulation badge&quot;">​</a></h3><p>When an S32 LFO is <strong>modulating</strong> this macro (not the same as “LFO parameter” macros), a <strong><code>~</code></strong> appears with the LFO number (e.g. <strong><code>~</code> / <code>1</code></strong>). Bright = that LFO is running; dim = assigned but off. See <a href="./../../concepts/modulation">Modulation</a>.</p><h3 id="live-value" tabindex="-1">Live value <a class="header-anchor" href="#live-value" aria-label="Permalink to &quot;Live value&quot;">​</a></h3><p>Right-aligned number from the current knob position — <strong>0–127</strong> for 7-bit modes, <strong>0–16383</strong> for 14-bit modes. If you narrowed min/max in edit mode, the value respects that range and the <a href="./../knob-view#macro-indicator-bars">indicator bar</a> may show gray bands at the limits.</p><h2 id="program-change-and-aftertouch" tabindex="-1">Program change and aftertouch <a class="header-anchor" href="#program-change-and-aftertouch" aria-label="Permalink to &quot;Program change and aftertouch&quot;">​</a></h2><p>Same layout as CC, but there is <strong>no controller number</strong> in the middle — only the <strong>PC</strong> or <strong>AT</strong> tag, <strong>channel</strong>, <strong>outputs</strong>, and <strong>value</strong>.</p><h2 id="name-a-control" tabindex="-1">Name a control <a class="header-anchor" href="#name-a-control" aria-label="Permalink to &quot;Name a control&quot;">​</a></h2><p>You can give any classic MIDI macro (CC, CC14, PC, AT, NRPN, RPN, SysEx) a <strong>custom name</strong>. When set, the name replaces the <strong>message type</strong> and <strong>controller/parameter</strong> columns, so the row reads like the thing it controls instead of a raw MIDI address. The <strong>channel</strong>, <strong>outputs</strong>, and <strong>live value</strong> stay exactly where they are.</p><p><img src="'+u+'" alt="Macro row with a custom control name" class="screen"></p><p>Long names are shortened with a trailing <code>…</code> so they never overrun the channel column.</p>',23)),e("p",null,[t[1]||(t[1]=r("To add, change, or remove a name, open the macro ",-1)),t[2]||(t[2]=e("strong",null,"side menu",-1)),t[3]||(t[3]=r(": in ",-1)),t[4]||(t[4]=e("a",{href:"./../edit-mode"},"edit mode",-1)),t[5]||(t[5]=r(", select a macro row and press ",-1)),o(s,{action:"select-long"}),t[6]||(t[6]=r()),o(s,{action:"back"}),t[7]||(t[7]=r()),t[8]||(t[8]=e("strong",null,"Select + Back",-1)),t[9]||(t[9]=r(".",-1))]),t[13]||(t[13]=n('<p><img src="'+p+'" alt="Macro side menu with name options" class="screen"></p><table tabindex="0"><thead><tr><th>Item</th><th>When shown</th><th>Action</th></tr></thead><tbody><tr><td><strong>Name Macro</strong></td><td>Row has no name</td><td>Opens the <a href="./../../macros/text-editor">text editor</a> to type a name</td></tr><tr><td><strong>Rename Macro</strong></td><td>Row already named</td><td>Reopens the editor with the current name</td></tr><tr><td><strong>Remove Name</strong></td><td>Row already named</td><td>Clears the name (asks to confirm) and restores the default layout</td></tr></tbody></table><p>Names are saved with the project.</p><h2 id="configure-these-macros" tabindex="-1">Configure these macros <a class="header-anchor" href="#configure-these-macros" aria-label="Permalink to &quot;Configure these macros&quot;">​</a></h2><ul><li><a href="./../../macros/control-change">Control Change</a> · <a href="./../../macros/fourteen-bit-cc">14-bit CC</a> · <a href="./../../macros/program-change">Program Change</a> · <a href="./../../macros/channel-aftertouch">Aftertouch</a> · <a href="./../../macros/nrpn">NRPN</a> · <a href="./../../macros/rpn">RPN</a></li></ul>',5)),o(i,null,{default:d(()=>[...t[10]||(t[10]=[e("ul",null,[e("li",null,[e("a",{href:"./"},"Macro rows overview")]),e("li",null,[e("a",{href:"./device-parameter"},"Device parameter rows"),r(" — Rack targets, no MIDI routing")]),e("li",null,[e("a",{href:"./../../concepts/modulation"},"Modulation"),r(" — Assign an LFO to a macro")])],-1)])]),_:1})])}const x=h(b,[["render",f]]);export{N as __pageData,x as default};
